const body = $input.first().json.body ?? $input.first().json;
// Slack Events API の URL 検証ハンドシェイク
if (body.type === 'url_verification') {
  return [{ json: { isChallenge: true, challenge: body.challenge, skip: true } }];
}
const TARGET = 'REPLACE_WITH_TRIGGER_EMOJI'; // 例: furikomi_done / paid / 振込完了
const ev = body.event || {};
if (ev.type !== 'reaction_added' || ev.reaction !== TARGET) {
  return [{ json: { skip: true, reason: 'not-target-reaction' } }];
}
if (!ev.item || ev.item.type !== 'message') {
  return [{ json: { skip: true, reason: 'not-message-item' } }];
}
return [{ json: { skip: false, isChallenge: false, channel: ev.item.channel, message_ts: ev.item.ts, reactor: ev.user } }];

const res = $input.first().json;
if (!res.ok) {
  return [{ json: { error: true, reason: 'slack-api:' + (res.error || 'unknown'), channel: $('Parse Slack Event').item.json.channel, message_ts: $('Parse Slack Event').item.json.message_ts } }];
}
const msgs = res.messages || [];
const parent = msgs[0] || {};
// 親メッセージ（請求書振込依頼）の PDF を請求書とみなす
let invoice = null;
for (const f of (parent.files || [])) {
  const t = (f.filetype || '').toLowerCase();
  if (t === 'pdf' || (f.mimetype || '') === 'application/pdf') { invoice = f; break; }
}
// スレッド返信の画像/PDF を「振込受付書」として全件収集（分割払い等で複数枚に対応）
const receipts = [];
for (let i = 1; i < msgs.length; i++) {
  for (const f of (msgs[i].files || [])) {
    const t = (f.filetype || '').toLowerCase();
    const m = (f.mimetype || '');
    if (m.indexOf('image/') === 0 || ['png','jpg','jpeg','heic','gif','pdf'].indexOf(t) >= 0) { receipts.push(f); }
  }
}
// 時系列（Slack 投稿順）を厳密化: ファイルのアップロード日時 created で昇順ソート
receipts.sort((a, b) => (a.created || 0) - (b.created || 0));
const channel = $('Parse Slack Event').item.json.channel;
const message_ts = $('Parse Slack Event').item.json.message_ts;
if (!invoice || receipts.length === 0) {
  return [{ json: { error: true, reason: 'missing-file', hasInvoice: !!invoice, receiptCount: receipts.length, channel, message_ts } }];
}
// ファイル名: YYYYMMDD_<請求書名>_振込受付書セット.pdf （JST）
const now = new Date(Date.now() + 9 * 3600 * 1000);
const ymd = now.toISOString().slice(0,10).split('-').join('');
let base = (invoice.title || invoice.name || 'invoice').replace(/\.pdf$/i,'');
for (const ch of ['/','\\',':','*','?','<','>','|']) { base = base.split(ch).join('_'); }
base = base.slice(0,80);
const filename = ymd + '_' + base + '_振込受付書セット.pdf';
// CloudConvert は Slack の非公開 URL を Authorization ヘッダ付きで取得する
const SLACK_AUTH = 'Bearer REPLACE_WITH_SLACK_BOT_TOKEN';
const tasks = {
  'import-invoice': { operation: 'import/url', url: invoice.url_private_download, headers: { Authorization: SLACK_AUTH } }
};
// 請求書を先頭に、受付書をスレッド投稿順で結合（画像は都度PDF化）
const mergeInputs = ['import-invoice'];
receipts.forEach((r, idx) => {
  const importName = 'import-receipt-' + idx;
  tasks[importName] = { operation: 'import/url', url: r.url_private_download, headers: { Authorization: SLACK_AUTH } };
  const isPdf = ((r.filetype || '').toLowerCase() === 'pdf') || ((r.mimetype || '') === 'application/pdf');
  if (isPdf) {
    mergeInputs.push(importName);
  } else {
    const convName = 'convert-receipt-' + idx;
    tasks[convName] = { operation: 'convert', input: importName, output_format: 'pdf' };
    mergeInputs.push(convName);
  }
});
tasks['merge'] = { operation: 'merge', input: mergeInputs, output_format: 'pdf', filename: filename };
tasks['export'] = { operation: 'export/url', input: 'merge', inline: false, archive_multiple_files: false };
return [{ json: { error: false, filename, channel, message_ts, invoice_name: invoice.title || invoice.name, receipt_count: receipts.length, ccJob: { tasks } } }];

const data = $input.first().json.data || {};
const tasks = data.tasks || [];
const exp = tasks.find(t => t.operation === 'export/url' && t.status === 'finished');
if (!exp || !exp.result || !exp.result.files || !exp.result.files.length) {
  return [{ json: { error: true, reason: 'no-export', status: data.status } }];
}
const src = $('Build CloudConvert Job').item.json;
return [{ json: { error: false, download_url: exp.result.files[0].url, filename: src.filename, channel: src.channel, message_ts: src.message_ts, invoice_name: src.invoice_name } }];
